source .venv/bin/activate && python3 << 'EOF'
# Test the temperature bump logic
MAX_RETRIES = 2

test_cases = [
    (0.0, "zero base"),
    (0.5, "mid temp"),
    (1.0, "max temp"),
    (0.9, "near-max"),
]

for base_temp, label in test_cases:
    print(f"\n{label} (base={base_temp}):")
    temps = [base_temp]
    for attempt in range(1, MAX_RETRIES + 1):
        bump = 0.2 * attempt
        if base_temp + bump <= 1.0:
            attempt_temp = base_temp + bump
        else:
            attempt_temp = max(0.0, base_temp - bump)
        temps.append(attempt_temp)
        print(f"  attempt {attempt}: bump={bump:.1f}, temp={attempt_temp:.1f}")

    # Check for duplicates
    if len(set(temps)) != len(temps):
        print(f"  ERROR: Duplicate temperatures detected!")
    else:
        print(f"  All {len(temps)} temperatures distinct: {temps}")

    # Check bounds
    for t in temps:
        if not (0.0 <= t <= 1.0):
            print(f"  ERROR: Temperature {t} out of bounds!")
EOF

